solution_code:
#define N 3

void simulate_priority(int burst[], int priority[], int n, int wait[], int turnaround[]) {
    int order[N];
    for (int i = 0; i < n; i++) order[i] = i;
    for (int i = 0; i < n - 1; i++)
        for (int j = 0; j < n - 1 - i; j++)
            if (priority[order[j]] > priority[order[j+1]]) {
                int tmp = order[j]; order[j] = order[j+1]; order[j+1] = tmp;
            }
    wait[order[0]] = 0;
    for (int i = 1; i < n; i++)
        wait[order[i]] = wait[order[i-1]] + burst[order[i-1]];
    for (int i = 0; i < n; i++)
        turnaround[i] = wait[i] + burst[i];
}

