void test_simulate_priority_single(void) {
    int burst[] = {4};
    int priority[] = {1};
    int wait[1], ta[1];
    simulate_priority(burst, priority, 1, wait, ta);
    TEST_ASSERT_EQUAL_INT(0, wait[0]);
    TEST_ASSERT_EQUAL_INT(4, ta[0]);
}

void test_simulate_priority_two_reversed(void) {
    int burst[] = {2, 3};
    int priority[] = {2, 1};
    int wait[2], ta[2];
    simulate_priority(burst, priority, 2, wait, ta);
    /* P2 (prio=1) executes first */
    TEST_ASSERT_EQUAL_INT(3, wait[0]);
    TEST_ASSERT_EQUAL_INT(0, wait[1]);
}

void test_simulate_priority_three_standard(void) {
    int burst[] = {3, 6, 3};
    int priority[] = {2, 1, 3};
    int wait[3], ta[3];
    simulate_priority(burst, priority, 3, wait, ta);
    /* Order: P2 (prio=1), P1 (prio=2), P3 (prio=3) */
    /* wait: P1=6, P2=0, P3=9 */
    TEST_ASSERT_EQUAL_INT(6, wait[0]);
    TEST_ASSERT_EQUAL_INT(0, wait[1]);
    TEST_ASSERT_EQUAL_INT(9, wait[2]);
}

void test_simulate_priority_equal(void) {
    int burst[] = {2, 2, 2};
    int priority[] = {1, 1, 1};
    int wait[3], ta[3];
    simulate_priority(burst, priority, 3, wait, ta);
    TEST_ASSERT_EQUAL_INT(0, wait[0]);
    TEST_ASSERT_EQUAL_INT(2, wait[1]);
    TEST_ASSERT_EQUAL_INT(4, wait[2]);
}

int main(void) {
    RUN_TEST(test_simulate_priority_single);
    RUN_TEST(test_simulate_priority_two_reversed);
    RUN_TEST(test_simulate_priority_three_standard);
    RUN_TEST(test_simulate_priority_equal);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

